window.__QUIZ_DATA__=[{"id":"objective>Government>1995>1","subject":"Government","year":"1995","type":"Objective","topic":"MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.","question":"The primary function of government in a state is to","images":[],"options":{"A":"Build schools and hospitals","B":"Provide transport service","C":"Engage in campaigns and rallies","D":"Maintain law and order"},"answer":"D","explanation":"The primary function of a government in a state is to maintain law and order. This is because the government is responsible for the enforcement of laws and regulations, and ensuring that all citizens abide by these laws. This helps to prevent chaos and disorder, and ensures the smooth running of the state. Building schools and hospitals, providing transport services, and engaging in campaigns and rallies are also functions of the government, but they are not the primary function.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>2","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"A country is most likely to have a good government only if it has","images":[],"options":{"A":"A Good constitution but bad operators","B":"Good operators but bad constitution","C":"A good constitution and good operators","D":"A legitimate government"},"answer":"D","explanation":"A legitimate government is one duly elected by the people.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>3","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"Which of the following is a basic principle of democracy? Rule by","images":[],"options":{"A":"The majority and the right of the minority","B":"The minority at the expense of the majority","C":"The wealthy few","D":"A monarch"},"answer":"A","explanation":"A basic principle of democracy is rule by the majority with respect for the rights of the minority. This means that while the majority's decision is followed, the rights and freedoms of the minority are still protected and respected.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>4","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES \u2013 RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION \u2013 (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).","question":"Which of the following is legal source of political authority?","images":[],"options":{"A":"Power from the gun","B":"Economic power","C":"Minority power","D":"Power from the electorate"},"answer":"D","explanation":"In a democratic society, the legal source of political authority is power from the electorate. This means that the people, through voting, give politicians the authority to govern. This is different from power from the gun (military power), economic power (wealth), or minority power (rule by a small group), which are not democratic sources of political authority.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>5","subject":"Government","year":"1995","type":"Objective","topic":"ORGANS OF GOVERNMENT : EXECUTIVE","question":"Which organ of government is vested with the responsibility of initiating bills and recommending them to the legislature for consideration? The","images":[],"options":{"A":"Federal House of Representatives","B":"Executive","C":"Congress","D":"Senate"},"answer":"B","explanation":"The Executive branch of government is responsible for initiating bills and recommending them to the legislature for consideration. The Executive branch includes the President, Vice President, and other executive officers to implement and enforce laws written by the legislature. The Federal House of Representatives, Congress, and Senate are all part of the legislative branch, not the executive.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>6","subject":"Government","year":"1995","type":"Objective","topic":"ORGANS OF GOVERNMENT : JUDICIARY","question":"The independence of the Judiciary can  be enhanced in all the following cases except where","images":[],"options":{"A":"Judges are granted special immunity","B":"Judges are paid handsome remuneration","C":"The President is also the Chief Judge","D":"The salaries of judges are drawn from consolidated fund"},"answer":"C","explanation":"The independence of the Judiciary can be compromised if the President is also the Chief Judge. This is because the separation of powers principle, which is fundamental to the operation of a democratic government, requires that the three branches of government - the executive, legislative, and judicial - operate independently of each other. If the President, who is part of the executive branch, is also the Chief Judge, this would violate the separation of powers and could potentially compromise the independence of the judiciary.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>7","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"Which of the following is a feature of feudalism?","images":[],"options":{"A":"One-party rule","B":"Multi-party system","C":"Millitary rule","D":"Lord-Serf relationship"},"answer":"D","explanation":"Feudalism is a social system that was prevalent in Medieval Europe under which, the nobility held lands from the Crown in exchange for military service, and vassals were in turn tenants of the nobles, while the peasants (villeins or serfs) were obliged to live on their lord's land and give him homage, labor, and a share of the produce, notionally in exchange for military protection. Therefore, the Lord-Serf relationship is a feature of feudalism.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>8","subject":"Government","year":"1995","type":"Objective","topic":"STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL","question":"Which of the following is the unique feature of Monarchy?","images":[],"options":{"A":"Members of the executive are popularl elected","B":"Succession is hereditary","C":"Separation of powers is absolute","D":"Its operation is based on collective responsibilty"},"answer":"B","explanation":"Monarchy is a form of government in which a single family rules from generation to generation. The power, or sovereignty, is often held by a single person, who is the monarch. A unique feature of monarchy is that the succession is hereditary, meaning that the throne is passed down to the monarch's descendants, usually from parent to child.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>9","subject":"Government","year":"1995","type":"Objective","topic":"STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET","question":"There is no seperation of powers in a Cabinet system because","images":[],"options":{"A":"Members of the Executive are also memebers of the Judiciary","B":"The President is also a member of parliament","C":"The Prime Minister and his cabinet ministers are also members of parliament","D":"Some elected parliamentarians are also judges"},"answer":"C","explanation":"In a Cabinet system of government, there is no complete separation of powers because the Prime Minister and his cabinet ministers are also members of parliament. This means that they are part of both the executive and legislative branches of government. The executive branch is responsible for implementing and enforcing laws, while the legislative branch is responsible for making laws. Therefore, the same individuals being part of both branches blurs the line of separation.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>10","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES \u2013 RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION \u2013 (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).","question":"In democracies, political participation could be restricted on the basis of","images":[],"options":{"A":"Religion","B":"Age","C":"Race","D":"Sex"},"answer":"B","explanation":"In democracies, political participation could be restricted on the basis of age. This is because there are usually minimum age requirements to vote or to run for office. For example, in many countries, you must be at least 18 years old to vote. Restrictions based on religion, race, or sex are generally considered undemocratic and are against the principles of equal rights and non-discrimination.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>11","subject":"Government","year":"1995","type":"Objective","topic":"THE ELECTORAL SYSTEM : MEANING AND PROCESSES","question":"Disenfranchisement refers to the","images":[],"options":{"A":"Qualification of voters in an election","B":"Disqualification of fraudulent persidential aspirants","C":"Denial of right to vote in an election","D":"`Right to vote in all elections"},"answer":"C","explanation":"Disenfranchisement refers to the denial of the right to vote in an election. It is a situation where a person or group of people are deprived of their voting rights. This can occur due to various reasons such as legal barriers, systemic barriers, or discrimination.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>12","subject":"Government","year":"1995","type":"Objective","topic":"CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE","question":"The limitation on the right to life can be found","images":[],"options":{"A":"Among the people","B":"In the case of a convicted person","C":"In the Executive","D":"In the Government"},"answer":"B","explanation":"The limitation on the right to life can be found in the case of a convicted person. This refers to the legal principle that a person's right to life can be limited or taken away by the state if they are convicted of a serious crime, such as murder. This is often the legal justification for capital punishment.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>13","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"Which of the following is not an agent of political socialization?","images":[],"options":{"A":"Tourism","B":"Mass media","C":"Peer group","D":"University"},"answer":"A","explanation":"Political socialization is the process by which individuals learn and frequently internalize a political lens framing their perceptions of how power is arranged and how the world around them is (and should be) organized. Those individuals are influenced by a variety of factors including family, school, peer group, and mass media. Tourism, however, is not typically considered an agent of political socialization.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>14","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"Political sovereignty belongs to","images":[],"options":{"A":"The people","B":"Students","C":"Soldiers","D":"The parliament"},"answer":"A","explanation":"Political sovereignty refers to the highest level of absolute power through which any independent state is governed. This power belongs to the people in a democratic system. The people exercise their power through voting in elections to choose their representatives in the parliament. Therefore, the correct answer is 'The people'.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>15","subject":"Government","year":"1995","type":"Objective","topic":"CITIZENSHIP : MEANING AND MODE OF ACQUISITION","question":"An alien who has lived in Nigeria for twenty years may acquire citizenship by","images":[],"options":{"A":"Nationlization","B":"Naturalization","C":"Registration","D":"Marriage"},"answer":"B","explanation":"Naturalization is \u200bthe process of making somebody who was not born in a particular country a citizen of that country.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>16","subject":"Government","year":"1995","type":"Objective","topic":"STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN","question":"In a republican parliamentary system of government, the ceremonial Head of State is the","images":[],"options":{"A":"Chief Justice","B":"Prime Minister","C":"President","D":"Party Leader"},"answer":"C","explanation":"In a republican parliamentary system of government, the ceremonial Head of State is the President. A republican parliamentary system is a type of government in which the head of state is an elected or nominated president rather than a monarch, while the legislature (parliament) holds the supreme power. The president in such a system serves largely ceremonial duties, as the real power lies with the parliament.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>17","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS \u2013 STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.","question":"Which of the following is not a feature of capitalism?","images":[],"options":{"A":"Free enterprise","B":"Private ownership of capital","C":"Minimal government intervention","D":"Profit maximization"},"answer":"A","explanation":"Capitalism is not a free enterprise. This is the most appropriate answer","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>18","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES \u2013 RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION \u2013 (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).","question":"A representative government can be established through","images":[],"options":{"A":"A general election","B":"A military coup","C":"An imposition","D":"Espionage"},"answer":"A","explanation":"A representative government is a system where citizens elect representatives to make laws on their behalf. This is typically done through a general election where citizens vote for their preferred candidates. A military coup, imposition, and espionage are not democratic means of establishing a representative government.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>19","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES \u2013 RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION \u2013 (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).","question":"Delegated legislation is suitable for","images":[],"options":{"A":"Relieving the parliarment of its work-load","B":"Enthroning the rule of law","C":"Ensuring the fusion of powers","D":"Checking the executive arm of government"},"answer":"A","explanation":"Delegated legislation is a type of legislation that is passed on by the Parliament to a person or body under its authority. This is done to relieve the Parliament of its workload as it cannot possibly handle all the details of complex legislation. Therefore, the correct answer is 'Relieving the parliament of its work-load'.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>20","subject":"Government","year":"1995","type":"Objective","topic":"BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES \u2013 RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION \u2013 (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).","question":"A necessary companion of the Rule of Law is","images":[],"options":{"A":"A special military tribunal","B":"The constant harassment of pressmen","C":"The supermacy of the ordinary law","D":"The trial of suspects in camera"},"answer":"C","explanation":"The Rule of Law is a principle that suggests that every individual, including the government, is subject to the law and that all are equal before the law. A necessary companion of the Rule of Law is the supremacy of the ordinary law, which means that no individual or government is above the law and everyone is subject to the same laws. Therefore, the correct answer is 'The supremacy of the ordinary law'.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>21","subject":"Government","year":"1995","type":"Objective","topic":"ORGANS OF GOVERNMENT : LEGISLATURE","question":"An appropriation bill is","images":[],"options":{"A":"State boundary adjustment bill","B":"A state creation bill","C":"Private member's bill","D":"A monetary bill"},"answer":"D","explanation":"An appropriation bill is a bill that authorizes the government to withdraw funds for use during the financial year.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>22","subject":"Government","year":"1995","type":"Objective","topic":"POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES","question":"A coalition government can be described as one which","images":[],"options":{"A":"Is made up of more than one political party","B":"Is formed by the political party that won the election","C":"Can effectively defend the nation","D":"Operates in a presidential system of government"},"answer":"A","explanation":"A coalition government is a form of government in which political parties cooperate, reducing the dominance of any one party within that coalition. The usual reason for this arrangement is that no party on its own can achieve a majority in the election. A coalition government might also be created in a time of national difficulty or crisis. Therefore, it is made up of more than one political party, hence option 1 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>23","subject":"Government","year":"1995","type":"Objective","topic":"PRE-COLONIAL POLITICAL SYSTEM : YORUBA","question":"One of the modern principles of government found in the traditional political system of Yoruba is that of","images":[],"options":{"A":"The constitution","B":"Checks and balances","C":"Bicameralism","D":"Multi-partism"},"answer":"B","explanation":"The traditional political system of the Yoruba people had a system of checks and balances. This was evident in the way power was distributed among the Oba (King), the council of chiefs, and the various societies and guilds. Each had its own sphere of influence and could check the excesses of the others. This is similar to the modern principle of checks and balances where power is distributed among the three arms of government - the executive, legislature, and judiciary - to prevent the abuse of power.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>24","subject":"Government","year":"1995","type":"Objective","topic":"PRE-COLONIAL POLITICAL SYSTEM : IGBO","question":"The function of the age-group in the Igbo pre-colonial society was to","images":[],"options":{"A":"Enforce laws and punish erring members","B":"Make laws for the people when an Ofo died","C":"Give judgement on land tenure matters","D":"Make sure that the religion of the people was observed"},"answer":"A","explanation":"In the Igbo pre-colonial society, the age-grade system was a significant institution. One of its primary functions was to enforce laws and punish erring members. The age-grade system was a form of social organization where individuals of the same age range formed a group with specific roles and responsibilities. These responsibilities included maintaining law and order, executing communal projects, and defending the community.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>25","subject":"Government","year":"1995","type":"Objective","topic":"PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA","question":"An important feature of the traditional government in West Africa was the Council of","images":[],"options":{"A":"Farmers","B":"Family Heads","C":"Elders","D":"Ministers"},"answer":"C","explanation":"In traditional West African societies, the Council of Elders was a significant feature. The Council of Elders was a group of respected individuals, usually older men, who had a wealth of experience and wisdom. They were responsible for making important decisions for the community, including settling disputes, making laws, and overseeing ceremonies. Therefore, the correct answer is 'Elders'.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>26","subject":"Government","year":"1995","type":"Objective","topic":"POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES","question":"A political party is mainly interested in","images":[],"options":{"A":"Contesting elections to gain power","B":"Opposing the governmnet in power","C":"Educating the public","D":"Formulating governmnet policies"},"answer":"A","explanation":"A political party is a group of people who share similar political views and work together to influence government policy and governance. The primary goal of a political party is to gain power by winning elections. This is because it is only when they are in power that they can implement their policies and ideas. Therefore, the correct answer is 'Contesting elections to gain power'.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>27","subject":"Government","year":"1995","type":"Objective","topic":"POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS","question":"The most important merit of a multi-system is that it","images":[],"options":{"A":"Guarantees the viability of many parties","B":"Disallows smaller political parties from gaining political power","C":"Reduces oppression within the various parties","D":"Gives representation to the widest shades of opinion and interest"},"answer":"D","explanation":"A multi-party system is a system in which multiple political parties across the political spectrum run for national election, and all have the capacity to gain control of government offices, separately or in coalition. The most important merit of a multi-party system is that it gives representation to the widest shades of opinion and interest. This is because in a multi-party system, different parties can represent different ideologies and interests, thus ensuring that a wide range of views are represented in the political process.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>28","subject":"Government","year":"1995","type":"Objective","topic":"PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS","question":"A pressure group can be defined as a","images":[],"options":{"A":"Large group interested in seizing polical power","B":"Group organized around an interest for governmental action","C":"Small group interested in sharing governmental power","D":"Sophisticated group interested in balkanization"},"answer":"B","explanation":"A pressure group is a group of people who are organized and actively try to influence public policy and especially government legislation about a specific issue or cause. They do not aim to become a government but they are interested in influencing governmental actions. Therefore, a pressure group can be defined as a group organized around an interest for governmental action.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>29","subject":"Government","year":"1995","type":"Objective","topic":"THE ELECTORAL SYSTEM : MEANING AND PROCESSES","question":"An election in which people vote for issues of public policy rather than candidates is known as a","images":[],"options":{"A":"Mini election","B":"General election","C":"Bye-election","D":"Referendum"},"answer":"D","explanation":"A referendum is a type of election where people vote on a single political question that has been referred to them for a direct decision. It is a form of direct democracy where citizens are given the power to decide on specific policy issues. The other options refer to different types of elections where candidates are voted for, not policy issues.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>30","subject":"Government","year":"1995","type":"Objective","topic":"THE ELECTORAL SYSTEM : MEANING AND PROCESSES","question":"Where no absolute majority is obtained in the first round of elections, the most viable option is the","images":[],"options":{"A":"Simple majority","B":"Proportional representation","C":"Second ballot","D":"Bye- election"},"answer":"C","explanation":"Second ballot refers to an electoral procedure where no candidate emerges as a clear winner in a first ballot, candidates at the bottom of the poll are eliminated and another ballot is held among the remaining candidates. Main objective of the Second Ballot system is to increase the chances of a candidate being elected on an absolute majority of the vote.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>31","subject":"Government","year":"1995","type":"Objective","topic":"THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY","question":"Which of the following is a function of Electoral Commisions?","images":[],"options":{"A":"Arbitrating among political parties","B":"Arranging and conducting elections","C":"Organizing political parties","D":"Supporting political parties"},"answer":"B","explanation":"The function of Electoral Commissions is to arrange and conduct elections. They are responsible for ensuring that elections are free, fair, and transparent. They do not arbitrate among political parties, organize political parties, or support political parties. Their role is purely administrative and regulatory.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>32","subject":"Government","year":"1995","type":"Objective","topic":"PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI","question":"The indirect Rule system succeeded in Hausa/Fulani society because the","images":[],"options":{"A":"Society had only one religion","B":"People recevied quranic education","C":"People were peaceful","D":"Existing administration favoured the system"},"answer":"D","explanation":"The indirect rule system succeeded in the Hausa/Fulani society because the existing administration favoured the system. The British colonial administration found it easier to govern through the existing traditional structures, which were already accepted and respected by the people. The fact that the society had only one religion, people received Quranic education, or people were peaceful were not the primary reasons for the success of the indirect rule system.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>33","subject":"Government","year":"1995","type":"Objective","topic":"COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION","question":"The policy of Association was adopted by the","images":[],"options":{"A":"British to replace their policy of Indirect Rule","B":"French to replace their policy of Assimilation","C":"British on their arrival in West Africa","D":"French on their departure from West Africa"},"answer":"B","explanation":"The Policy of Association was the second policy of the French Colonial Administration which recognized and preserved the identity, traditions, institutions, religions, customs, and way of life of the people within the French empire. This policy was emphasized by the French between 1920-1945.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>34","subject":"Government","year":"1995","type":"Objective","topic":"NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.","question":"Nationalism in Africa eventually led to","images":[],"options":{"A":"A rapid political awareness among the colonialists","B":"The alignment of the new states","C":"De-colonization","D":"The formation of a continental army"},"answer":"C","explanation":"Nationalism in Africa eventually led to de-colonization. Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. In the context of Africa, nationalism was a significant force for the end of colonial rule and the achievement of independence by African nations. It led to the rise of anti-colonial political movements that sought and eventually succeeded in gaining independence for their nations.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>35","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS","question":"One major achievement of the Richards Constitution of Nigeria was that it","images":[],"options":{"A":"United the North and South under a single Legislature","B":"Introduced the elective principle","C":"Provided for official African majority in the Legislature","D":"Made more Africans member of the Executive council"},"answer":"A","explanation":"Richards constitution of 1946 solved the problem of legislating for the North by proclamation. A central legislature was created in which all the regions were being represented. The constitution also created regional assemblies in the Northern, Western and Eastern regions.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>36","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS","question":"The 1954 Constitution of Nigeria made the country a true Federation because it provided for","images":[],"options":{"A":"The abolition of representation of white officials","B":"The election of all members of parliament","C":"A division of functions between the centre and the regions","D":"The post of a Prime Minister at the centre"},"answer":"C","explanation":"The 1954 Constitution of Nigeria made the country a true Federation by providing for a division of functions between the centre and the regions. This meant that each region had its own government and was responsible for certain aspects of governance, while the central government was responsible for matters of national importance. This is a key feature of a federal system of government.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>37","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS","question":"The Chicks Commission in Nigeria was up to look into the issue of","images":[],"options":{"A":"Revenue allocation","B":"Minority groups","C":"State creation","D":"Constitutional amendment"},"answer":"A","explanation":"The Chicks Commission was set up in Nigeria to look into the issue of Revenue allocation. The commission was established in 1953 by the British colonial government to examine and recommend ways of sharing revenue between the regional and central government in Nigeria.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>38","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS","question":"The decision to separate Lagos from the Western Region and make it a neutral Federal territory was taken at the","images":[],"options":{"A":"1950 general conference","B":"1953 constitutional conference","C":"1954 constitutional conference","D":"1957 constitutional conference"},"answer":"B","explanation":"The conference which sat between July 30 and August 22, 1953, reached the agreement that Lagos should be separated from the Western region and made a neutral federal territory.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>39","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONS : DEFINITION AND SOURCES","question":"Which of the following was not required of  Presidential candidate for the 1979 election in Nigeria? He must","images":[],"options":{"A":"Be a Nigerian citizen by birth","B":"Be an indigene of one of the northern states","C":"Be sponsored by a registered political party","D":"Have paid his income tax for three years as and when due"},"answer":"B","explanation":"The 1979 constitution of Nigeria did not require a presidential candidate to be an indigene of one of the northern states. The requirements were: he must be a Nigerian citizen by birth, be sponsored by a registered political party, and have paid his income tax for three years as and when due.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>40","subject":"Government","year":"1995","type":"Objective","topic":"STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET","question":"Between 1960 and 1980, Nigeria experienced all the following systems of government except","images":[],"options":{"A":"Unitary","B":"Federal","C":"Confederal","D":"Parliamentary"},"answer":"C","explanation":"Between 1960 and 1980, Nigeria experienced Unitary, Federal, and Parliamentary systems of government. However, it did not experience a Confederal system of government. In a confederal system, the constituent states retain a large degree of independence and sovereignty, with the central government only coordinating and not controlling the states.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>41","subject":"Government","year":"1995","type":"Objective","topic":"COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION","question":"The first Head of State and Head of Government in Nigeria was","images":[],"options":{"A":"Lord Frederich Lugard","B":"Alhaji Abubakar Tafawa Balewa","C":"Alhaji Shehu Shagari","D":"Gen. J.T.U. Aguiyi-Ironsi"},"answer":"C","explanation":"Alhaji Shehu Shagari was the first executive president of Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>42","subject":"Government","year":"1995","type":"Objective","topic":"CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS","question":"The functions of the Governor-General in Nigeria after independence did not include","images":[],"options":{"A":"The dismissal of Ministers","B":"Ceremonial functions","C":"The appointment of the Prime Minister","D":"The granting of pardon"},"answer":"C","explanation":"The governor general did not appoint the prime minister.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>43","subject":"Government","year":"1995","type":"Objective","topic":"DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME","question":"Which of the following was the first political party in Nigeria? The","images":[],"options":{"A":"Action Group (AG)","B":"Northern People's congress (NPC)","C":"National Council for Nigeria and the Camerouns (NCNC)","D":"Nigerian National Democratic Party (NNDP)"},"answer":"D","explanation":"The Nigerian National Democratic Party (NNDP) was the first political party in Nigeria. It was formed in 1923 by Herbert Macaulay.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>44","subject":"Government","year":"1995","type":"Objective","topic":"STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL","question":"Which of the following is not true of a federal system of government?","images":[],"options":{"A":"There are three legislature lists","B":"Powers are not constitutionally shared","C":"There are component units","D":"The constitution is written and rigid"},"answer":"B","explanation":"In a federal system of government, powers are constitutionally shared between the central government and the component units. This is one of the key features of a federal system. Therefore, the statement 'Powers are not constitutionally shared' is not true of a federal system of government.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>45","subject":"Government","year":"1995","type":"Objective","topic":"DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME","question":"The main criticism against pre-independence political parties in Nigeria was that they","images":[],"options":{"A":"Were not national outlook","B":"Had no manifestos","C":"Did not contribute to political development","D":"Did not educate the electorate"},"answer":"A","explanation":"The main criticism against pre-independence political parties in Nigeria was that they were not national in outlook. This means that they were often based on regional or ethnic lines, rather than representing the interests of the entire country. This led to a lack of unity and cohesion in the political landscape, which in turn hindered the development of a strong and stable national identity.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>46","subject":"Government","year":"1995","type":"Objective","topic":"DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES","question":"Which of the following did not generate political crises in Nigeria? The","images":[],"options":{"A":"Motion for self government in 1956 by Enahoro","B":"Adoption of Abuja as the new Federal Capital","C":"Head count of 1962","D":"1964 General Elections"},"answer":"B","explanation":"The adoption of Abuja as the new Federal Capital did not generate political crises in Nigeria. The other options, such as the motion for self government in 1956 by Enahoro, the head count of 1962, and the 1964 General Elections, all led to significant political crises due to disagreements and conflicts between different political groups and regions. However, the decision to move the capital from Lagos to Abuja was largely accepted and did not lead to any major political conflicts.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>47","subject":"Government","year":"1995","type":"Objective","topic":"MILITARY RULE : VARIOUS MILITARY REGIMES","question":"The major policy of General Gowon's administration immediately after the Nigerian civil war was","images":[],"options":{"A":"Restructuring ,Reoccurrence and Reconciliation","B":"National Economic Restructuring","C":"Reconstruction Reconciliation and Rehabilitation","D":"Structural Adjustment Programme"},"answer":"C","explanation":"Gowon subsequently declared his famous \"no victor, no vanquished\" speech, and followed it up with an amnesty for the majority of those who had participated in the Biafran uprising, as well as a program of \"Reconciliation, Reconstruction, and Rehabilitation\"","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>48","subject":"Government","year":"1995","type":"Objective","topic":"DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES","question":"Which of the following was not an election issue in Nigeria during the Second Republic ?","images":[],"options":{"A":"Change of the colour of Naira","B":"Creation of more local governments","C":"Provision of free education","D":"Provision of more houses"},"answer":"A","explanation":"During the Second Republic in Nigeria, the change of the colour of Naira was not an election issue. The issues that were prominent during the elections were related to socio-economic and political matters such as creation of more local governments, provision of free education and provision of more houses.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>49","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : ECOWAS","question":"Which of the following countries was not involved in the peace-keeping effort in Liberia ?","images":[],"options":{"A":"Ghana","B":"Nigeria","C":"Sierra Leone","D":"Cameroun"},"answer":"D","explanation":"The peacekeeping effort in Liberia was led by the Economic Community of West African States (ECOWAS) under the banner of the ECOWAS Monitoring Group (ECOMOG). The main contributors to this force were Nigeria, Ghana, and Sierra Leone. Cameroun was not involved in the peacekeeping effort in Liberia.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>50","subject":"Government","year":"1995","type":"Objective","topic":"MILITARY RULE : VARIOUS MILITARY REGIMES","question":"The first military Head of State in Nigeria was General","images":[],"options":{"A":"Muhammadu Buhari","B":"Olusegun Obasanjo","C":"Aguiyi-lronsi","D":"Yakubu Gowon"},"answer":"C","explanation":"The first military Head of State in Nigeria was Major General Johnson Thomas Umunnakwe Aguiyi-Ironsi. He took over power after the 1966 coup d'etat that overthrew the first republic. The other options listed were also military heads of state but they came into power after Aguiyi-Ironsi.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>51","subject":"Government","year":"1995","type":"Objective","topic":"PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS","question":"Which of the following is a feature of public corporation ? It","images":[],"options":{"A":"Provides social services and amenities","B":"Has a Director -General as head of General Administration","C":"Is set up to make profit","D":"Has a minister as the administrative head"},"answer":"A","explanation":"A public corporation is a company that is owned by the government, and its main purpose is to provide services to the public. It is not primarily set up to make profit, but to provide social services and amenities. Therefore, the correct answer is option 1.","marks":"1","difficulty":"1"},{"id":"objective>Government>1995>52","subject":"Government","year":"1995","type":"Objective","topic":"PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS","question":"One of the problem facing local government in Nigeria is the","images":[],"options":{"A":"Withdrawal of grants by the central governmnent","B":"Interference from the central government","C":"Inclusion of traditional rulers in the local government council","D":"Lack of personnel"},"answer":"B","explanation":"Local governments in Nigeria often face interference from the central government. This interference can take many forms, including the central government dictating policies and decisions, or exerting control over local government finances. Therefore, the correct answer is option 2.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>53","subject":"Government","year":"1995","type":"Objective","topic":"PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS","question":"Local governments are essential because they","images":[],"options":{"A":"Encouage division in the country","B":"Check abuse of office by governmnet functionaries","C":"Implement government policies at the local level","D":"Make laws for the nation"},"answer":"C","explanation":"Local governments are essential because they implement government policies at the local level. They are the closest tier of government to the people and they play a key role in the implementation of government policies at the grassroots level. They do not make laws for the nation, that is the role of the legislative arm of government at the national level. They also do not encourage division in the country or check abuse of office by government functionaries, these are not their primary roles.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>54","subject":"Government","year":"1995","type":"Objective","topic":"FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES","question":"The goal which a state aspires to achieve in its relation with other states may be referred to as","images":[],"options":{"A":"Diplomatic interest","B":"National policy","C":"National interest","D":"Political independence"},"answer":"C","explanation":"National Interests can as defined as the claims, objectives, goals, demands and interests which a nation always tries to preserve, protect, defend and secure in relation with other states.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>55","subject":"Government","year":"1995","type":"Objective","topic":"FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES","question":"Nigeria's foreign policy came into the limelight at independence because","images":[],"options":{"A":"Nigeria did not know any other country before then","B":"Only at independence do States proclaim their foreign policy principles","C":"Her internal policies were harsh","D":"Nigeria was self-sufficient before independence"},"answer":"B","explanation":"At independence, states usually proclaim their foreign policy principles. This is because they are now sovereign and can make decisions that affect their relations with other countries. Foreign policy is a strategy or approach chosen by national governments to achieve their international goals. Nigeria's foreign policy came into the limelight at independence because it was at this point that Nigeria began to interact with other nations as a sovereign state, hence the need to establish its foreign policy principles.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>56","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : AFRICAN UNION","question":"Which of the following has the Organization of African Unity (OAU) failed to achieve?","images":[],"options":{"A":"Setting up an African High Command","B":"Setting border disputes in Africa","C":"Giving assistance to liberation movernmnets in African","D":"Contributing to the economic and social development of member states"},"answer":"A","explanation":"The Organization of African Unity (OAU), now the African Union (AU), has failed to achieve the setting up of an African High Command. The African High Command was proposed as a collective security arrangement to provide for the defense of any African state under attack. However, due to various reasons such as national sovereignty concerns and lack of consensus among member states, the idea has not been realized.","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>57","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : ECOWAS","question":"ECOWAS was set up purely for","images":[],"options":{"A":"Political advantages","B":"Social adavantages","C":"Economic adavantages","D":"Historical advantages"},"answer":"C","explanation":"The Economic Community of West African States (ECOWAS) was established to promote economic integration across countries in the West African region. Therefore, it was set up for economic advantages.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>58","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : AFRICAN UNION","question":"The resolutions and programmes of the OAU are executed by the","images":[],"options":{"A":"Secretariat","B":"Commission of Mediation Councilation and Arbitration","C":"Head of Government of each member state","D":"Council of Ministers"},"answer":"C","explanation":"They form the executive arm of the organization. This is the accurate answer","marks":"1","difficulty":"3"},{"id":"objective>Government>1995>59","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO","question":"All the following organs/agencies of the United Nations Organization have their headquarters situated in New York except the","images":[],"options":{"A":"United Nations Development Projects (UNDP)","B":"World Health Organization (WHO)","C":"International Court of Justice (ICJ)","D":"United Nations Educational, Seientific and Cutural Organization (UNESCO)"},"answer":"C","explanation":"The International Court of Justice (ICJ) is not headquartered in New York, but in The Hague, Netherlands. The ICJ is the principal judicial organ of the United Nations (UN). It settles legal disputes between member states and gives advisory opinions to authorized UN organs and specialized agencies.","marks":"1","difficulty":"2"},{"id":"objective>Government>1995>60","subject":"Government","year":"1995","type":"Objective","topic":"INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO","question":"One of the objective of the United Nations Organization (UNO) is to","images":[],"options":{"A":"Develop the African States","B":"Maintain International peace and security","C":"Ensure that workers all over the world are paid handsome wages and salaries","D":"Provide ammunition for any warring states"},"answer":"B","explanation":"One of the main objectives of the United Nations Organization (UNO) is to maintain international peace and security. This is stated in the UN Charter, which is the foundational treaty of the United Nations. The UN does this by working to prevent conflict; helping parties in conflict make peace; peacekeeping; and creating the conditions to allow peace to hold and flourish.","marks":"1","difficulty":"1"}];